import React, { useState, useEffect } from "react";
import { Authors } from '../../Authors'
import { Videos } from '../../Videos';
import VideoPlayer from "../VideoPlayer";
//import { contractData } from '../../api';
import Arweave from "arweave";
import { SmartWeaveNodeFactory } from "redstone-smartweave";
import './videoPlayerContainer.css';


export function VideoPlayerContainer (props){
 
let videoID = new URL(window.location.href).pathname.split('/').at(-1);
let video = Videos[videoID];
let author = Authors[video.authorID];
const [isLoading, setIsLoading] = useState(true);

// const awaiting = contractData().then((data) => {return data}).catch((e) => {console.log(e)});
// console.log(awaiting,"-------------------------------------------");

    useEffect(() => {
      setIsLoading(false)
    }, []);

    async function getData() {
      const arweave = await Arweave.init({
        host: "arweave.net",
        port: 443,
        protocol: "https",
        timeout: 100000,
        logging: false,
      });
    
      const providersRegistryContractTxId =
        "urbw9dve61V1h-hRf_nEHJBVLa3Vv8J08vhY2GnvLlY";
    
      const smartweave = SmartWeaveNodeFactory.memCachedBased(arweave).build();
    
      // 'connecting' to a given contract, using its txId
      const { state, validity } = await smartweave
        .contract(providersRegistryContractTxId)
        .readState();
    
      console.log("Result", {
        state,
        validity,
      },
      
      );
      return { state, validity };
    }
    //setVideoData(data.state)
    getData().then((data) => {console.log(data.state)}
    ).catch((e) => {console.log(e)});

    let src = video.videoSrc;
    if (!isLoading) {
      return (
        <div className="video-player-container">
          <header className="video-header">
            
            <h2 className="video-title">{video.videoTitle}</h2>
          </header>
          <div className="video-player">
            <VideoPlayer src={src}/>
          </div>

          <footer className="video-footer">
            <h2>To learn more about {author.author}</h2>
            <p className="videoLink"> Visit their page   
              <a href={author.authorWebsite} target="_blank"
                rel="noreferrer" className='video-creator-link'>
                   HERE 
              </a>
            </p>
            <p>Video Creator :
              <a href={author.authorLink}
                className="video-creator-link"
                target="_blank"
                rel="noreferrer"
              >
                {video.description}
              </a>
            </p>
          </footer>
        </div>
      );
    }
    return null;
  }
  export default VideoPlayerContainer;

